import{_ as n,W as s,X as a,Y as t}from"./framework-30063720.js";const e={},p=t(`<h2 id="_1-功能" tabindex="-1"><a class="header-anchor" href="#_1-功能" aria-hidden="true">#</a> 1. 功能</h2><p>设置响应消息，包括响应行、响应头、响应体的数据。</p><h2 id="_2-设置响应行" tabindex="-1"><a class="header-anchor" href="#_2-设置响应行" aria-hidden="true">#</a> 2. 设置响应行</h2><p>主要是来设置状态码，使用<code>setStatus(int sc)</code>方法。</p><h2 id="_3-设置响应头" tabindex="-1"><a class="header-anchor" href="#_3-设置响应头" aria-hidden="true">#</a> 3. 设置响应头</h2><p>使用<code>setHeader(String name, String value)</code>方法。</p><h2 id="_4-设置响应体" tabindex="-1"><a class="header-anchor" href="#_4-设置响应体" aria-hidden="true">#</a> 4. 设置响应体</h2><ol><li><p>获取输出流；</p><ul><li>字符输出流，使用<code>PrintWriter getWriter()</code>方法；</li><li>字节输出流，使用<code>ServletOutputStream getOutputStream()</code>方法。</li></ul></li><li><p>使用输出流，将数据输出到客户端浏览器。</p></li></ol><h2 id="_5-response的更多使用" tabindex="-1"><a class="header-anchor" href="#_5-response的更多使用" aria-hidden="true">#</a> 5. Response的更多使用</h2><h3 id="_5-1-重定向" tabindex="-1"><a class="header-anchor" href="#_5-1-重定向" aria-hidden="true">#</a> 5.1. 重定向</h3><h4 id="_5-1-1-概念" tabindex="-1"><a class="header-anchor" href="#_5-1-1-概念" aria-hidden="true">#</a> 5.1.1. 概念</h4><p>资源跳转的一种方式。</p><figure><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/java/JavaWeb/9.Response-Introduction202303311202784.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h4 id="_5-1-2-使用" tabindex="-1"><a class="header-anchor" href="#_5-1-2-使用" aria-hidden="true">#</a> 5.1.2. 使用</h4><ul><li>核心代码：</li></ul><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token comment">//重定向，访问 /responseDemo1 路径会自动跳转到 /responseDemo2 路径。</span>
<span class="token comment">/*
//1.设置状态码为302
resp.setStatus(302);
//2.设置响应头location
resp.setHeader(&quot;location&quot;,&quot;/today/responseDemo2&quot;);
*/</span>
<span class="token comment">//更简单的重定向，一般都使用该种方式</span>
resp<span class="token punctuation">.</span><span class="token function">sendRedirect</span><span class="token punctuation">(</span><span class="token string">&quot;/today/responseDemo2&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>请求转发是一种在服务器内部的资源跳转方式。</p><p>这里需要和请求转发区分开：请求转发的路径不会变，状态码为200，拥有共享域对象，只能在服务器内部进行跳转；重定向的路径会变，状态码为302，没有共享域对象，可跳转服务器内部和外部的资源。</p></blockquote><h4 id="_5-1-3-重定向和转发的区别" tabindex="-1"><a class="header-anchor" href="#_5-1-3-重定向和转发的区别" aria-hidden="true">#</a> 5.1.3. 重定向和转发的区别</h4><h5 id="_5-1-3-1-重定向-redirect" tabindex="-1"><a class="header-anchor" href="#_5-1-3-1-重定向-redirect" aria-hidden="true">#</a> 5.1.3.1. 重定向(redirect)</h5><ol><li>地址栏发生变化，状态码为302；</li><li>重定向可以访问当前服务器内部和其他站点(服务器外部)的资源；</li><li>重定向是两次请求，有两个request对象，不能使用request对象来共享数据；</li><li>路径需要加虚拟目录。</li></ol><h5 id="_5-1-3-2-转发-forward" tabindex="-1"><a class="header-anchor" href="#_5-1-3-2-转发-forward" aria-hidden="true">#</a> 5.1.3.2. 转发(forward)</h5><ol><li>转发地址栏路径不变，状态码为200；</li><li>转发只能访问当前服务器内部的资源；</li><li>转发是一次请求，可以使用request对象来共享数据；</li><li>路径不需要加虚拟目录。</li></ol><blockquote><p>请求转发的更多解析可到文章servlet&amp;http&amp;request中的[请求转发]({% post_path &#39;JavaWEB-4.Servlet&amp;HTTP&amp;Request-note&#39; %}#请求转发)查看。</p></blockquote><h3 id="_5-2-服务器输出字符数据-string-到浏览器" tabindex="-1"><a class="header-anchor" href="#_5-2-服务器输出字符数据-string-到浏览器" aria-hidden="true">#</a> 5.2. 服务器输出字符数据(String)到浏览器</h3><h4 id="_5-2-1-使用步骤" tabindex="-1"><a class="header-anchor" href="#_5-2-1-使用步骤" aria-hidden="true">#</a> 5.2.1. 使用步骤</h4><ol><li>获取字符输出流</li><li>输出数据</li></ol><blockquote><p>一般用于服务器输出文本信息、HTML代码块到浏览器。</p></blockquote><h4 id="_5-2-2-乱码问题" tabindex="-1"><a class="header-anchor" href="#_5-2-2-乱码问题" aria-hidden="true">#</a> 5.2.2. 乱码问题</h4><ol><li><code>PrintWriter pw = response.getWriter();</code>获取的流的默认编码是ISO-8859-1；</li><li>设置该流的默认编码；</li><li>告诉浏览器响应体使用的编码。</li></ol><p>简单的形式设置编码，是在获取流之前设置，使用代码：<code>response.setContentType(&quot;text/html;charset=utf-8&quot;);</code>。</p><h4 id="_5-2-3-核心代码" tabindex="-1"><a class="header-anchor" href="#_5-2-3-核心代码" aria-hidden="true">#</a> 5.2.3. 核心代码</h4><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">package</span> <span class="token namespace">io<span class="token punctuation">.</span>gitee<span class="token punctuation">.</span>hek97<span class="token punctuation">.</span>web<span class="token punctuation">.</span>servlet</span><span class="token punctuation">;</span>
<span class="token comment">//去掉了导包的代码</span>

<span class="token annotation punctuation">@WebServlet</span><span class="token punctuation">(</span><span class="token string">&quot;/responseDemo3&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">ResponseDemo3</span> <span class="token keyword">extends</span> <span class="token class-name">HttpServlet</span> <span class="token punctuation">{</span>
    <span class="token annotation punctuation">@Override</span>
    <span class="token keyword">protected</span> <span class="token keyword">void</span> <span class="token function">doPost</span><span class="token punctuation">(</span><span class="token class-name">HttpServletRequest</span> request<span class="token punctuation">,</span> <span class="token class-name">HttpServletResponse</span> response<span class="token punctuation">)</span> <span class="token keyword">throws</span> <span class="token class-name">ServletException</span><span class="token punctuation">,</span> <span class="token class-name">IOException</span> <span class="token punctuation">{</span>
        <span class="token comment">//获取流对象之前，设置流的编码</span>
        <span class="token comment">//response.setCharacterEncoding(&quot;utf-8&quot;);该行可省略，下一行设置响应头中编码的代码会间接设置流的编码。</span>
        <span class="token comment">//告诉浏览器，服务器发送的消息体数据的编码，建议浏览器使用该编码解码，这里使用的是设置响应头中编码的方法</span>
        response<span class="token punctuation">.</span><span class="token function">setHeader</span><span class="token punctuation">(</span><span class="token string">&quot;content-type&quot;</span><span class="token punctuation">,</span><span class="token string">&quot;text/html;charset=utf-8&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token comment">//1.获取字符输出流</span>
        <span class="token class-name">PrintWriter</span> pw <span class="token operator">=</span> response<span class="token punctuation">.</span><span class="token function">getWriter</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token comment">//2.输出数据</span>
        pw<span class="token punctuation">.</span><span class="token function">write</span><span class="token punctuation">(</span><span class="token string">&quot;你好,response&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token annotation punctuation">@Override</span>
    <span class="token keyword">protected</span> <span class="token keyword">void</span> <span class="token function">doGet</span><span class="token punctuation">(</span><span class="token class-name">HttpServletRequest</span> request<span class="token punctuation">,</span> <span class="token class-name">HttpServletResponse</span> response<span class="token punctuation">)</span> <span class="token keyword">throws</span> <span class="token class-name">ServletException</span><span class="token punctuation">,</span> <span class="token class-name">IOException</span> <span class="token punctuation">{</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span><span class="token function">doPost</span><span class="token punctuation">(</span>request<span class="token punctuation">,</span> response<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_5-3-服务器输出字节数据-byte-到浏览器" tabindex="-1"><a class="header-anchor" href="#_5-3-服务器输出字节数据-byte-到浏览器" aria-hidden="true">#</a> 5.3. 服务器输出字节数据(Byte)到浏览器</h3><h4 id="_5-3-1-使用步骤" tabindex="-1"><a class="header-anchor" href="#_5-3-1-使用步骤" aria-hidden="true">#</a> 5.3.1. 使用步骤</h4><ol><li>获取字节输出流</li><li>输出数据</li></ol><blockquote><p>一般用于从服务器输出图片到浏览器。</p></blockquote><h4 id="_5-3-2-核心代码" tabindex="-1"><a class="header-anchor" href="#_5-3-2-核心代码" aria-hidden="true">#</a> 5.3.2. 核心代码</h4><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">package</span> <span class="token namespace">io<span class="token punctuation">.</span>gitee<span class="token punctuation">.</span>hek97<span class="token punctuation">.</span>web<span class="token punctuation">.</span>servlet</span><span class="token punctuation">;</span>

<span class="token comment">//省略导包代码</span>

<span class="token annotation punctuation">@WebServlet</span><span class="token punctuation">(</span><span class="token string">&quot;/responseDemo4&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">ResponseDemo4</span> <span class="token keyword">extends</span> <span class="token class-name">HttpServlet</span> <span class="token punctuation">{</span>
    <span class="token annotation punctuation">@Override</span>
    <span class="token keyword">protected</span> <span class="token keyword">void</span> <span class="token function">doPost</span><span class="token punctuation">(</span><span class="token class-name">HttpServletRequest</span> request<span class="token punctuation">,</span> <span class="token class-name">HttpServletResponse</span> response<span class="token punctuation">)</span> <span class="token keyword">throws</span> <span class="token class-name">ServletException</span><span class="token punctuation">,</span> <span class="token class-name">IOException</span> <span class="token punctuation">{</span>
        <span class="token comment">//设置响应消息编码</span>
        response<span class="token punctuation">.</span><span class="token function">setHeader</span><span class="token punctuation">(</span><span class="token string">&quot;content-type&quot;</span><span class="token punctuation">,</span><span class="token string">&quot;text/html;charset=utf-8&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token comment">//1.获取字节输出流</span>
        <span class="token class-name">ServletOutputStream</span> sos <span class="token operator">=</span> response<span class="token punctuation">.</span><span class="token function">getOutputStream</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token comment">//2.输出数据</span>
        sos<span class="token punctuation">.</span><span class="token function">write</span><span class="token punctuation">(</span><span class="token string">&quot;你好&quot;</span><span class="token punctuation">.</span><span class="token function">getBytes</span><span class="token punctuation">(</span><span class="token string">&quot;utf-8&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token annotation punctuation">@Override</span>
    <span class="token keyword">protected</span> <span class="token keyword">void</span> <span class="token function">doGet</span><span class="token punctuation">(</span><span class="token class-name">HttpServletRequest</span> request<span class="token punctuation">,</span> <span class="token class-name">HttpServletResponse</span> response<span class="token punctuation">)</span> <span class="token keyword">throws</span> <span class="token class-name">ServletException</span><span class="token punctuation">,</span> <span class="token class-name">IOException</span> <span class="token punctuation">{</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span><span class="token function">doPost</span><span class="token punctuation">(</span>request<span class="token punctuation">,</span> response<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_5-4-练习-验证码" tabindex="-1"><a class="header-anchor" href="#_5-4-练习-验证码" aria-hidden="true">#</a> 5.4. 练习：验证码</h3><p>本质就是一张图片，为了防止恶意表单注册。</p><h4 id="_5-4-1-使用步骤" tabindex="-1"><a class="header-anchor" href="#_5-4-1-使用步骤" aria-hidden="true">#</a> 5.4.1. 使用步骤</h4><ol><li>在内存中生成一张图片</li><li>美化图片</li><li>输出图片</li></ol><h4 id="_5-4-2-核心代码" tabindex="-1"><a class="header-anchor" href="#_5-4-2-核心代码" aria-hidden="true">#</a> 5.4.2. 核心代码</h4><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">package</span> <span class="token namespace">io<span class="token punctuation">.</span>gitee<span class="token punctuation">.</span>hek97<span class="token punctuation">.</span>web<span class="token punctuation">.</span>servlet</span><span class="token punctuation">;</span>

<span class="token comment">//去除导包代码</span>

<span class="token annotation punctuation">@WebServlet</span><span class="token punctuation">(</span><span class="token string">&quot;/demo&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">CheckCodeServlet</span> <span class="token keyword">extends</span> <span class="token class-name">HttpServlet</span> <span class="token punctuation">{</span>
    <span class="token annotation punctuation">@Override</span>
    <span class="token keyword">protected</span> <span class="token keyword">void</span> <span class="token function">doPost</span><span class="token punctuation">(</span><span class="token class-name">HttpServletRequest</span> request<span class="token punctuation">,</span> <span class="token class-name">HttpServletResponse</span> response<span class="token punctuation">)</span> <span class="token keyword">throws</span> <span class="token class-name">ServletException</span><span class="token punctuation">,</span> <span class="token class-name">IOException</span> <span class="token punctuation">{</span>
        <span class="token keyword">int</span> width <span class="token operator">=</span> <span class="token number">100</span><span class="token punctuation">;</span>
        <span class="token keyword">int</span> height <span class="token operator">=</span> <span class="token number">50</span><span class="token punctuation">;</span>
        <span class="token comment">//1.创建对象，在内存中存图片（验证码）对象</span>
        <span class="token class-name">BufferedImage</span> image <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">BufferedImage</span><span class="token punctuation">(</span>width<span class="token punctuation">,</span> height<span class="token punctuation">,</span> <span class="token class-name">BufferedImage</span><span class="token punctuation">.</span><span class="token constant">TYPE_3BYTE_BGR</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token comment">//2.美化图片</span>
        <span class="token comment">//2.1填充背景色</span>
        <span class="token class-name">Graphics</span> g <span class="token operator">=</span> image<span class="token punctuation">.</span><span class="token function">getGraphics</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//获取画笔对象</span>
        g<span class="token punctuation">.</span><span class="token function">setColor</span><span class="token punctuation">(</span><span class="token class-name">Color</span><span class="token punctuation">.</span><span class="token constant">PINK</span><span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//设置画笔颜色</span>
        g<span class="token punctuation">.</span><span class="token function">fillRect</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span><span class="token number">0</span><span class="token punctuation">,</span>width<span class="token punctuation">,</span>height<span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//设置填充范围</span>
        <span class="token comment">//2.2画边框</span>
        g<span class="token punctuation">.</span><span class="token function">setColor</span><span class="token punctuation">(</span><span class="token class-name">Color</span><span class="token punctuation">.</span><span class="token constant">BLUE</span><span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//设置画笔颜色</span>
        g<span class="token punctuation">.</span><span class="token function">drawRect</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span><span class="token number">0</span><span class="token punctuation">,</span>width<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">,</span>height<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//设置边框范围</span>
        <span class="token class-name">String</span> str <span class="token operator">=</span><span class="token string">&quot;ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789&quot;</span><span class="token punctuation">;</span>
        <span class="token comment">//生成随机角标</span>
        <span class="token class-name">Random</span> ran <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Random</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//获取随机数对象</span>
        <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span> i <span class="token operator">&lt;=</span> <span class="token number">4</span><span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token keyword">int</span> index <span class="token operator">=</span> ran<span class="token punctuation">.</span><span class="token function">nextInt</span><span class="token punctuation">(</span>str<span class="token punctuation">.</span><span class="token function">length</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//生成随机数</span>
            <span class="token keyword">char</span> ch <span class="token operator">=</span> str<span class="token punctuation">.</span><span class="token function">charAt</span><span class="token punctuation">(</span>index<span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//获取相应位置的字符</span>
            <span class="token comment">//2.3写验证码</span>
            g<span class="token punctuation">.</span><span class="token function">drawString</span><span class="token punctuation">(</span>ch<span class="token operator">+</span><span class="token string">&quot;&quot;</span><span class="token punctuation">,</span>width<span class="token operator">/</span><span class="token number">5</span><span class="token operator">*</span>i<span class="token punctuation">,</span>height<span class="token operator">/</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span>
        <span class="token comment">//2.4画干扰线</span>
        g<span class="token punctuation">.</span><span class="token function">setColor</span><span class="token punctuation">(</span><span class="token class-name">Color</span><span class="token punctuation">.</span><span class="token constant">GREEN</span><span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//设置画笔颜色</span>
        <span class="token comment">//画10条干扰线</span>
        <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> <span class="token number">10</span><span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token comment">//随机生成坐标点</span>
            <span class="token keyword">int</span> x1<span class="token operator">=</span>ran<span class="token punctuation">.</span><span class="token function">nextInt</span><span class="token punctuation">(</span>width<span class="token punctuation">)</span><span class="token punctuation">;</span>
            <span class="token keyword">int</span> x2<span class="token operator">=</span>ran<span class="token punctuation">.</span><span class="token function">nextInt</span><span class="token punctuation">(</span>width<span class="token punctuation">)</span><span class="token punctuation">;</span>
            <span class="token keyword">int</span> y1<span class="token operator">=</span>ran<span class="token punctuation">.</span><span class="token function">nextInt</span><span class="token punctuation">(</span>height<span class="token punctuation">)</span><span class="token punctuation">;</span>
            <span class="token keyword">int</span> y2<span class="token operator">=</span>ran<span class="token punctuation">.</span><span class="token function">nextInt</span><span class="token punctuation">(</span>height<span class="token punctuation">)</span><span class="token punctuation">;</span>
            <span class="token comment">//画1条干扰线</span>
            g<span class="token punctuation">.</span><span class="token function">drawLine</span><span class="token punctuation">(</span>x1<span class="token punctuation">,</span>x2<span class="token punctuation">,</span>y1<span class="token punctuation">,</span>y2<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span>
        <span class="token comment">//3.将图片输出到页面展示</span>
        <span class="token class-name">ImageIO</span><span class="token punctuation">.</span><span class="token function">write</span><span class="token punctuation">(</span>image<span class="token punctuation">,</span><span class="token string">&quot;jpg&quot;</span><span class="token punctuation">,</span>response<span class="token punctuation">.</span><span class="token function">getOutputStream</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token annotation punctuation">@Override</span>
    <span class="token keyword">protected</span> <span class="token keyword">void</span> <span class="token function">doGet</span><span class="token punctuation">(</span><span class="token class-name">HttpServletRequest</span> request<span class="token punctuation">,</span> <span class="token class-name">HttpServletResponse</span> response<span class="token punctuation">)</span> <span class="token keyword">throws</span> <span class="token class-name">ServletException</span><span class="token punctuation">,</span> <span class="token class-name">IOException</span> <span class="token punctuation">{</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span><span class="token function">doPost</span><span class="token punctuation">(</span>request<span class="token punctuation">,</span>response<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_5-4-3-使用代码" tabindex="-1"><a class="header-anchor" href="#_5-4-3-使用代码" aria-hidden="true">#</a> 5.4.3. 使用代码</h4><p>在网页中使用验证码，并实现点击图片切换验证码的功能。</p><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token comment">&lt;!--login.html--&gt;</span>
<span class="token doctype"><span class="token punctuation">&lt;!</span><span class="token doctype-tag">DOCTYPE</span> <span class="token name">html</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>html</span> <span class="token attr-name">lang</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>en<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">
    window<span class="token punctuation">.</span><span class="token function-variable function">onload</span><span class="token operator">=</span><span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token comment">//1.获取图片对象</span>
        <span class="token keyword">var</span> img <span class="token operator">=</span>document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&quot;checkCode&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token comment">//2.绑定单击事件</span>
        img<span class="token punctuation">.</span><span class="token function-variable function">onclick</span><span class="token operator">=</span><span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token comment">//加时间戳</span>
            <span class="token keyword">var</span> date <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Date</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">getTime</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
            img<span class="token punctuation">.</span>src <span class="token operator">=</span> <span class="token string">&quot;/today/demo?&quot;</span><span class="token operator">+</span>date<span class="token punctuation">;</span><span class="token comment">//时间戳可以防止浏览器认读取本地缓存的图片</span>
        <span class="token punctuation">}</span>

    <span class="token punctuation">}</span>
</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>head</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>meta</span> <span class="token attr-name">charset</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>UTF-8<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>title</span><span class="token punctuation">&gt;</span></span>点击图片切换验证码<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>title</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>head</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>body</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>img</span> <span class="token attr-name">id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>checkCode<span class="token punctuation">&quot;</span></span> <span class="token attr-name">src</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>/today/demo<span class="token punctuation">&quot;</span></span><span class="token punctuation">/&gt;</span></span>//点击图片切换验证码
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>body</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>html</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_6-相对路径和绝对路径" tabindex="-1"><a class="header-anchor" href="#_6-相对路径和绝对路径" aria-hidden="true">#</a> 6. 相对路径和绝对路径</h2><h3 id="_6-1-相对路径" tabindex="-1"><a class="header-anchor" href="#_6-1-相对路径" aria-hidden="true">#</a> 6.1. 相对路径</h3><h4 id="_6-1-1-概念" tabindex="-1"><a class="header-anchor" href="#_6-1-1-概念" aria-hidden="true">#</a> 6.1.1. 概念</h4><p>通过相对路径不可以确定唯一资源，如：<code>./index.html</code>，一般以.开头的路径，其中的<code>./</code>也可以省略。</p><h4 id="_6-1-2-使用规则" tabindex="-1"><a class="header-anchor" href="#_6-1-2-使用规则" aria-hidden="true">#</a> 6.1.2. 使用规则</h4><p>找到当前资源和目标资源之间的相对位置关系。</p><blockquote><p>常用的有<code>./</code>：当前目录，<code>../</code>：上一级目录。</p></blockquote><h3 id="_6-2-绝对路径" tabindex="-1"><a class="header-anchor" href="#_6-2-绝对路径" aria-hidden="true">#</a> 6.2. 绝对路径</h3><h4 id="_6-2-1-概念" tabindex="-1"><a class="header-anchor" href="#_6-2-1-概念" aria-hidden="true">#</a> 6.2.1. 概念</h4><p>通过绝对路径可以确定唯一资源，如：<code>http://localhost/day15/responseDemo2</code>，因为服务器地址是一样的，所以可简化书写为：<code>/day15/responseDemo2</code>，以/开头。</p><h4 id="_6-2-2-使用规则" tabindex="-1"><a class="header-anchor" href="#_6-2-2-使用规则" aria-hidden="true">#</a> 6.2.2. 使用规则</h4><p>通过判断定义的路径是给谁使用的？</p><ul><li>给客户端（浏览器）使用：需要加虚拟目录(项目的访问路径)，相当于在教学楼门前叫张三，需要指明具体是那个班级的张三。 <ul><li>建议虚拟目录动态获取，一但虚拟目录发生改变可以动态获取，不用修改，使用<code>request.getContextPath()</code>方法；例如重定向推荐使用：<code>resp.sendRedirect(req.getContextPath()+&quot;/responseDemo2&quot;);</code>。</li></ul></li></ul><blockquote><p>Html中虚拟目录的获取在之后的jsp中学习<code>&lt;a&gt;</code> ,<code>&lt;form&gt;</code>。</p></blockquote><ul><li>给服务器内部使用：不需要加虚拟目录，相当于在班级门前叫张三，直接喊就可以了。</li></ul><blockquote><p>可以判断请求将来从哪儿发出，从客户端还是服务器端内部发出，比如转发是从服务器内部发出的，不需要加虚拟目录，重定向是两次请求，由客户端发出，需要加虚拟目录。</p></blockquote><figure><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/java/JavaWeb/9.Response-Introduction202303311202548.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure>`,64),o=[p];function c(l,i){return s(),a("div",null,o)}const r=n(e,[["render",c],["__file","9.Response-Introduction.html.vue"]]);export{r as default};
